const keywordItems = $('Set Keywords').all();
const searchResultItems = $input.all();
const allVideos = [];
const seenIds = new Set();

for (let i = 0; i < searchResultItems.length; i++) {
  const keyword = keywordItems[i]?.json?.keyword || ('keyword_' + i);
  const responseItems = searchResultItems[i]?.json?.items || [];
  for (const video of responseItems) {
    const videoId = video.id?.videoId;
    if (!videoId || seenIds.has(videoId)) continue;
    seenIds.add(videoId);
    allVideos.push({
      json: {
        videoId,
        keyword,
        title: video.snippet?.title || 'Unknown Title',
        channelId: video.snippet?.channelId || '',
        channelTitle: video.snippet?.channelTitle || '',
        publishedAt: video.snippet?.publishedAt || '',
        thumbnail: video.snippet?.thumbnails?.high?.url ||
                   video.snippet?.thumbnails?.medium?.url ||
                   ('https://img.youtube.com/vi/' + videoId + '/hqdefault.jpg')
      }
    });
  }
}
if (allVideos.length === 0) return [{ json: { videoId: '_placeholder', keyword: 'none' } }];
return allVideos;

const BATCH_SIZE = 50;
const allIds = $input.all()
  .filter(item => item.json.videoId && item.json.videoId !== '_placeholder')
  .map(item => item.json.videoId);
const uniqueIds = [...new Set(allIds)];
const batches = [];
for (let i = 0; i < uniqueIds.length; i += BATCH_SIZE) {
  batches.push({
    json: {
      videoIdBatch: uniqueIds.slice(i, i + BATCH_SIZE).join(','),
      batchNum: Math.floor(i / BATCH_SIZE) + 1
    }
  });
}
if (batches.length === 0) return [{ json: { videoIdBatch: '', batchNum: 0 } }];
return batches;

const allDetails = [];
const seenIds = new Set();

for (const item of $input.all()) {
  for (const video of (item.json.items || [])) {
    if (seenIds.has(video.id)) continue;
    seenIds.add(video.id);
    const views = parseInt(video.statistics?.viewCount || '0');
    const likes = parseInt(video.statistics?.likeCount || '0');
    const comments = parseInt(video.statistics?.commentCount || '0');
    const engagementRate = views > 0 ? parseFloat(((likes + comments) / views * 100).toFixed(3)) : 0;
    allDetails.push({
      videoId: video.id,
      title: video.snippet?.title || '',
      channelId: video.snippet?.channelId || '',
      channelTitle: video.snippet?.channelTitle || '',
      publishedAt: video.snippet?.publishedAt || '',
      thumbnail: video.snippet?.thumbnails?.high?.url ||
                 video.snippet?.thumbnails?.medium?.url ||
                 ('https://img.youtube.com/vi/' + video.id + '/hqdefault.jpg'),
      tags: (video.snippet?.tags || []).slice(0, 10),
      description: (video.snippet?.description || '').substring(0, 300),
      views, likes, comments, engagementRate,
      duration: video.contentDetails?.duration || ''
    });
  }
}

// Relevance filtering: check if video contains relevant keywords
const relevanceKeywords = [
  'automation', 'ai agent', 'workflow', 'n8n', 'make.com', 'zapier',
  'agentic', 'orchestration', 'llm', 'chatbot', 'business automation',
  'no-code', 'low-code'
];

const filteredDetails = allDetails.filter(video => {
  const searchText = (
    video.title.toLowerCase() + ' ' +
    video.description.toLowerCase() + ' ' +
    video.tags.join(' ').toLowerCase()
  );
  return relevanceKeywords.some(keyword => searchText.includes(keyword));
});

// Use filtered videos if we have enough, otherwise fall back to all
const videosToRank = filteredDetails.length >= 10 ? filteredDetails : allDetails;

videosToRank.sort((a, b) => b.views - a.views);
const top50 = videosToRank.slice(0, 50);
const top10 = top50.slice(0, 10);

const searchVideos = $('Flatten Videos').all();
const videoKeywordMap = {};
for (const item of searchVideos) {
  if (item.json.videoId) videoKeywordMap[item.json.videoId] = item.json.keyword || 'other';
}
for (const v of top50) v.keyword = videoKeywordMap[v.videoId] || 'other';

const channelMap = {};
for (const v of top50) {
  if (!channelMap[v.channelId]) {
    channelMap[v.channelId] = { channelId: v.channelId, channelTitle: v.channelTitle, videoCount: 0, totalViews: 0, topVideo: null };
  }
  channelMap[v.channelId].videoCount++;
  channelMap[v.channelId].totalViews += v.views;
  if (!channelMap[v.channelId].topVideo || v.views > channelMap[v.channelId].topVideo.views) {
    channelMap[v.channelId].topVideo = { title: v.title, views: v.views, videoId: v.videoId };
  }
}
const topChannels = Object.values(channelMap).sort((a, b) => b.totalViews - a.totalViews).slice(0, 10);

const keywordCounts = {};
for (const v of videosToRank) {
  const kw = videoKeywordMap[v.videoId] || 'other';
  keywordCounts[kw] = (keywordCounts[kw] || 0) + 1;
}

const reportDate = new Date().toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

return [{ json: { top10Videos: top10, top50Videos: top50, topChannels, keywordCounts, totalVideosAnalyzed: videosToRank.length, reportDate } }];

// Reads ranked video data from Rank Videos node
// Passes spreadsheetUrl (from Finalize Spreadsheet) through to downstream nodes
const data = $('Rank Videos').first().json;
const spreadsheetUrl = $json.spreadsheetUrl || '';

// Defensive: ensure we always have objects/arrays
const top50Videos = Array.isArray(data.top50Videos) ? data.top50Videos : [];
const topChannels = Array.isArray(data.topChannels) ? data.topChannels : [];
const keywordCounts = data.keywordCounts && typeof data.keywordCounts === 'object'
  ? data.keywordCounts
  : {};

const top20 = top50Videos.slice(0, 20);
const totalVideosAnalyzed = Number(data.totalVideosAnalyzed || 0);

const videoSummary = top20.map((v, i) =>
  (i + 1) + '. "' + (v.title || 'Untitled') + '" by ' + (v.channelTitle || 'Unknown') +
  ' | Views: ' + Number(v.views || 0).toLocaleString() +
  ' | Engagement: ' + (v.engagementRate ?? 'N/A') + '%' +
  ' | Published: ' + (v.publishedAt ? new Date(v.publishedAt).toLocaleDateString() : 'N/A') +
  ' | Tags: ' + (Array.isArray(v.tags) ? v.tags : []).slice(0, 5).join(', ')
).join('\n');

const channelSummary = topChannels.slice(0, 5).map(c =>
  '- ' + (c.channelTitle || 'Unknown') + ': ' +
  Number(c.videoCount || 0) + ' videos, ' +
  Number(c.totalViews || 0).toLocaleString() + ' combined views'
).join('\n');

const kwSummary = Object.entries(keywordCounts)
  .sort((a, b) => b[1] - a[1])
  .map(([k, v]) => k + ': ' + v + ' videos')
  .join(', ');

const prompt = [
  'You are an expert AI/YouTube content strategist. Analyze this data from the past 7 days in the AI & automation niche.',
  '',
  'TOP 20 TRENDING VIDEOS:',
  videoSummary,
  '',
  'TOP CHANNELS THIS WEEK:',
  channelSummary,
  '',
  'VIDEO COUNT BY KEYWORD: ' + kwSummary,
  'TOTAL VIDEOS ANALYZED: ' + totalVideosAnalyzed,
  '',
  'Respond with ONLY valid JSON (no markdown code blocks) in this exact structure:',
  '{',
  '  "executiveSummary": ["bullet1","bullet2","bullet3","bullet4","bullet5"],',
  '  "trendingTopics": [{"topic":"Name","description":"Why trending and what angle creators take","examples":["title1","title2","title3"]}],',
  '  "contentRecommendations": [{"title":"Video Title Idea","rationale":"Why this would perform well","targetKeywords":["kw1","kw2","kw3"]}],',
  '  "spaceSentiment": "2-3 sentence overview of the AI content space mood this week",',
  '  "channelInsights": "3-4 sentences on what top channels are doing right"',
  '}',
  '',
  'Include EXACTLY 5 trendingTopics and EXACTLY 6 contentRecommendations.',
  'Base ALL analysis on the actual data provided. No generic filler content.',
  'Each executiveSummary bullet should be 20-40 words of actionable insight.'
].join('\n');

return [{ json: { prompt, spreadsheetUrl } }];

// runOnceForAllItems
// Consolidates back to single item with spreadsheet URL
const spreadsheetId = $('Create Analytics Spreadsheet').first().json.spreadsheetId;
const spreadsheetUrl = 'https://docs.google.com/spreadsheets/d/' + spreadsheetId;
return [{ json: { spreadsheetUrl, spreadsheetId } }];

const data = $('Rank Videos').first().json;
const spreadsheetId = $('Create Analytics Spreadsheet').first().json.spreadsheetId;
const topChannels = data.topChannels || [];
const top50 = data.top50Videos || [];
const reportDate = data.reportDate || new Date().toLocaleDateString();

const channelKeywords = {};
const channelEngagement = {};
for (const v of top50) {
  const cid = v.channelId;
  if (!channelKeywords[cid]) channelKeywords[cid] = {};
  const kw = v.keyword || 'other';
  channelKeywords[cid][kw] = (channelKeywords[cid][kw] || 0) + 1;
  if (!channelEngagement[cid]) channelEngagement[cid] = { total: 0, count: 0 };
  channelEngagement[cid].total += (v.engagementRate || 0);
  channelEngagement[cid].count++;
}

return topChannels.map(c => {
  const kwMap = channelKeywords[c.channelId] || {};
  const sorted = Object.entries(kwMap).sort((a, b) => b[1] - a[1]);
  const avgViews = c.videoCount > 0 ? Math.round(c.totalViews / c.videoCount) : 0;
  const eng = channelEngagement[c.channelId];
  const avgEng = eng && eng.count > 0 ? parseFloat((eng.total / eng.count).toFixed(2)) : 0;
  return {
    json: {
      spreadsheetId,
      "Date": reportDate,
      "Channel ID": c.channelId,
      "Title": c.channelTitle,
      "Subscribers": "",
      "Total Views": c.totalViews,
      "Avg Views": avgViews,
      "Engagement %": avgEng,
      "Top Keyword": sorted[0] ? sorted[0][0] : "",
      "Top Keyword 2": sorted[1] ? sorted[1][0] : ""
    }
  };
});

const data = $('Rank Videos').first().json;
const spreadsheetId = $('Create Analytics Spreadsheet').first().json.spreadsheetId;
const top50 = data.top50Videos || [];
const topChannels = data.topChannels || [];
const reportDate = data.reportDate || new Date().toLocaleDateString();

const channelVideoCount = {};
for (const c of topChannels) channelVideoCount[c.channelId] = c.videoCount || 0;

const now = new Date();
return top50.map(v => {
  const publishedDays = v.publishedAt
    ? Math.floor((now - new Date(v.publishedAt)) / (1000 * 60 * 60 * 24))
    : "";
  const tags = Array.isArray(v.tags) ? v.tags : [];
  const kw2 = tags.find(t => t.toLowerCase() !== (v.keyword || '').toLowerCase()) || (tags[1] || "");
  return {
    json: {
      spreadsheetId,
      "Date": reportDate,
      "Channel ID": v.channelId,
      "Title": v.title,
      "Subscribers": "",
      "Total Views": v.views,
      "Avg Views": v.views,
      "Engagement %": v.engagementRate,
      "Top Keyword": v.keyword || "",
      "Top Keyword 2": kw2,
      "Published Days": publishedDays,
      "Uploads": channelVideoCount[v.channelId] || "",
      "Engagement Rate": v.engagementRate,
      "Tags": tags.join(", ")
    }
  };
});

const data = $('Rank Videos').first().json;
const spreadsheetId = $('Create Analytics Spreadsheet').first().json.spreadsheetId;
const top50 = data.top50Videos || [];
const reportDate = data.reportDate || new Date().toLocaleDateString();
const now = new Date();

const kwStats = {};
for (const v of top50) {
  const kw = v.keyword || 'other';
  if (!kwStats[kw]) kwStats[kw] = { views: 0, engagement: 0, count: 0, publishedDays: 0, titles: [] };
  kwStats[kw].views += (v.views || 0);
  kwStats[kw].engagement += (v.engagementRate || 0);
  kwStats[kw].count++;
  if (v.publishedAt) kwStats[kw].publishedDays += Math.floor((now - new Date(v.publishedAt)) / (1000 * 60 * 60 * 24));
  kwStats[kw].titles.push(v.title);
}

const sortedKw = Object.entries(kwStats).sort((a, b) => b[1].views - a[1].views);
const topKw1 = sortedKw[0] ? sortedKw[0][0] : "";
const topKw2 = sortedKw[1] ? sortedKw[1][0] : "";

return sortedKw.map(([kw, stats]) => {
  const avgViews = stats.count > 0 ? Math.round(stats.views / stats.count) : 0;
  const avgEng = stats.count > 0 ? parseFloat((stats.engagement / stats.count).toFixed(2)) : 0;
  const avgDays = stats.count > 0 ? Math.round(stats.publishedDays / stats.count) : 0;
  return {
    json: {
      spreadsheetId,
      "Date": reportDate,
      "Channel ID": "",
      "Title": kw,
      "Subscribers": "",
      "Total Views": stats.views,
      "Avg Views": avgViews,
      "Engagement %": avgEng,
      "Top Keyword": topKw1,
      "Top Keyword 2": topKw2,
      "Published Days": avgDays,
      "Uploads": stats.count,
      "Engagement Rate": avgEng,
      "Content Table": stats.titles.slice(0, 3).join(" | ")
    }
  };
});

const videoData = $('Rank Videos').first().json;
const top10 = videoData.top10Videos || [];
const topChannels = videoData.topChannels || [];
const keywordCounts = videoData.keywordCounts || {};
const reportDate = videoData.reportDate || new Date().toLocaleDateString();
const totalVideosAnalyzed = videoData.totalVideosAnalyzed || 0;
const top50 = videoData.top50Videos || [];

// Logo embedded as base64 data URI
const logoDataUri = 'data:image/png;base64,';

let analysis = {};
try {
  // "Message a model" node outputs at $json.output[0].content[0].text
  const raw = $json.output?.[0]?.content?.[0]?.text || $json.text || $json.content?.[0]?.text || $json.choices?.[0]?.message?.content || '{}';
  // Try direct parse first (AI usually returns clean JSON)
  try { analysis = JSON.parse(raw); } catch (_directErr) {
    // Fallback: strip markdown code fences, then extract outermost JSON object
    const stripped = raw.replace(/```json\s*/g, '').replace(/```\s*/g, '');
    const jsonStart = stripped.indexOf('{');
    const jsonEnd = stripped.lastIndexOf('}');
    if (jsonStart >= 0 && jsonEnd > jsonStart) {
      analysis = JSON.parse(stripped.substring(jsonStart, jsonEnd + 1));
    }
  }
} catch (e) {
  analysis = {
    executiveSummary: ['Analysis unavailable \u2014 check AI API credentials and retry'],
    trendingTopics: [],
    contentRecommendations: [],
    spaceSentiment: 'N/A',
    channelInsights: 'N/A'
  };
}

function fmt(n) {
  if (n >= 1000000) return (n / 1000000).toFixed(1) + 'M';
  if (n >= 1000) return (n / 1000).toFixed(0) + 'K';
  return String(n);
}

function fmtDate(iso) {
  if (!iso) return '';
  return new Date(iso).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
}

function esc(s) {
  return String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function truncate(s, max) {
  if (!s) return '';
  return s.length > max ? s.substring(0, max - 1) + '\u2026' : s;
}

function encodeChart(cfg) {
  return 'https://quickchart.io/chart?c=' + encodeURIComponent(JSON.stringify(cfg)) + '&w=800&h=400&backgroundColor=%23000000&format=png';
}

const palette = [
  'rgba(226,242,61,0.85)', 'rgba(74,222,128,0.85)', 'rgba(167,139,250,0.85)',
  'rgba(251,146,60,0.85)', 'rgba(56,189,248,0.85)', 'rgba(244,114,182,0.85)',
  'rgba(45,212,191,0.85)', 'rgba(253,224,71,0.85)'
];

// Chart 1: Top 10 by views (truncate labels to 20 chars to keep URL short)
const c1 = {
  type: 'horizontalBar',
  data: {
    labels: top10.map(v => truncate(v.title, 20)),
    datasets: [{
      data: top10.map(v => v.views),
      backgroundColor: 'rgba(226,242,61,0.85)',
      borderColor: 'rgba(226,242,61,1)',
      borderWidth: 1
    }]
  },
  options: {
    legend: { display: false },
    scales: {
      xAxes: [{ ticks: { fontColor: '#9ca3af' }, gridLines: { color: '#1a1a1a' } }],
      yAxes: [{ ticks: { fontColor: '#FFFFFF', fontSize: 9 }, gridLines: { color: '#1a1a1a' } }]
    }
  }
};

// Chart 2: Engagement by topic
const topicsEng = {};
for (const v of top50) {
  const kw = v.keyword || 'other';
  if (!topicsEng[kw]) topicsEng[kw] = { total: 0, count: 0 };
  topicsEng[kw].total += v.engagementRate;
  topicsEng[kw].count++;
}
const engList = Object.entries(topicsEng)
  .map(([k, v]) => ({ label: k, avg: parseFloat((v.total / v.count).toFixed(2)) }))
  .sort((a, b) => b.avg - a.avg).slice(0, 8);

const c2 = {
  type: 'bar',
  data: {
    labels: engList.map(t => truncate(t.label, 14)),
    datasets: [{ label: 'Avg Eng %', data: engList.map(t => t.avg), backgroundColor: palette }]
  },
  options: {
    title: { display: true, text: 'Average Engagement Rate by Topic', fontColor: '#E2F23D', fontSize: 11 },
    legend: { display: false },
    scales: {
      xAxes: [{ ticks: { fontColor: '#9ca3af', fontSize: 8 }, gridLines: { color: '#1a1a1a' } }],
      yAxes: [{ ticks: { fontColor: '#9ca3af' }, gridLines: { color: '#1a1a1a' } }]
    }
  }
};

// Chart 3: Volume by keyword
const kwEntries = Object.entries(keywordCounts).sort((a, b) => b[1] - a[1]).slice(0, 8);
const c3 = {
  type: 'doughnut',
  data: {
    labels: kwEntries.map(([k]) => truncate(k, 14)),
    datasets: [{ data: kwEntries.map(([, v]) => v), backgroundColor: palette }]
  },
  options: {
    title: { display: true, text: 'Video Volume by Search Keyword', fontColor: '#E2F23D', fontSize: 11 },
    legend: { position: 'right', labels: { fontColor: '#9ca3af', fontSize: 9, padding: 8 } }
  }
};

const chartUrl1 = encodeChart(c1);
const chartUrl2 = encodeChart(c2);
const chartUrl3 = encodeChart(c3);

// ── HTML Components ──

const statsItems = [
  { num: String(totalVideosAnalyzed), label: 'VIDEOS ANALYZED' },
  { num: String(top10.length), label: 'TOP TRENDING' },
  { num: String(topChannels.length), label: 'CHANNELS' },
  { num: String(Object.keys(keywordCounts).length), label: 'KEYWORDS' }
];

const statsHtml = statsItems.map((s, i) =>
  '<div style="flex:1;text-align:center;padding:16px 8px">' +
    '<div style="font-size:28px;font-weight:bold;color:#E2F23D">' + s.num + '</div>' +
    '<div style="font-family:Courier New,monospace;font-size:6.5px;color:#9ca3af;margin-top:4px;letter-spacing:0.5px">' + s.label + '</div>' +
  '</div>' + (i < 3 ? '<div style="width:1px;background:#374151;margin:8px 0"></div>' : '')
).join('');

const videoCards = top10.map((v, i) =>
  '<div style="display:flex;align-items:flex-start;padding:10px 16px;border-radius:4px;margin-bottom:3px;background:' + (i % 2 === 0 ? '#111' : '#1a1a1a') + '">' +
    '<div style="font-size:16px;font-weight:bold;color:#E2F23D;width:32px;flex-shrink:0;margin-top:2px">' + String(i + 1).padStart(2, '0') + '</div>' +
    '<div style="flex:1">' +
      '<div style="font-size:9.5px;font-weight:bold;color:#fff;margin-bottom:2px">' + esc(truncate(v.title, 74)) + '</div>' +
      '<div style="font-size:8px;color:#9ca3af;margin-bottom:6px">' + esc(truncate(v.channelTitle, 40)) + '</div>' +
      '<div style="display:flex;gap:5px;flex-wrap:wrap">' +
        '<span style="font-family:Courier New,monospace;font-size:6.5px;padding:2px 6px;border-radius:6px;background:#374151;color:#E2F23D">' + fmt(v.views) + ' views</span>' +
        '<span style="font-family:Courier New,monospace;font-size:6.5px;padding:2px 6px;border-radius:6px;background:#374151;color:#4ade80">' + v.engagementRate + '% eng</span>' +
        '<span style="font-family:Courier New,monospace;font-size:6.5px;padding:2px 6px;border-radius:6px;background:#374151;color:#9ca3af">' + fmtDate(v.publishedAt) + '</span>' +
        '<span style="font-family:Courier New,monospace;font-size:6.5px;padding:2px 6px;border-radius:6px;background:#374151;color:#a78bfa">' + esc(truncate(v.keyword, 18)) + '</span>' +
      '</div>' +
    '</div>' +
  '</div>'
).join('');

const exBullets = (analysis.executiveSummary || []).map(b =>
  '<div style="display:flex;margin-bottom:16px;align-items:flex-start">' +
    '<span style="font-family:Courier New,monospace;font-weight:bold;font-size:11px;color:#E2F23D;margin-right:12px;flex-shrink:0">-&gt;</span>' +
    '<span style="font-size:10.5px;color:#fff;line-height:1.6">' + esc(b) + '</span>' +
  '</div>'
).join('');

const topicsHtml = (analysis.trendingTopics || []).map(t =>
  '<div style="background:#1a1a1a;border-radius:4px;padding:16px 16px 16px 20px;margin-bottom:10px;border-left:3px solid #E2F23D">' +
    '<div style="font-size:11px;font-weight:bold;color:#E2F23D;margin-bottom:4px">' + esc(t.topic || '') + '</div>' +
    '<div style="font-size:9.5px;color:#fff;line-height:1.5;margin-bottom:4px">' + esc(t.description || '') + '</div>' +
    (t.examples?.length ? '<div style="font-size:8px;font-style:italic;color:#6b7280">e.g. \u201c' + t.examples.map(e => esc(e)).join('\u201d, \u201c') + '\u201d</div>' : '') +
  '</div>'
).join('');

const chRows = topChannels.slice(0, 8).map((c, i) =>
  '<tr style="background:' + (i % 2 === 0 ? '#111' : '#1a1a1a') + '">' +
    '<td style="padding:8px;color:#E2F23D">' + (i + 1) + '</td>' +
    '<td style="padding:8px;color:#fff;font-weight:bold">' + esc(truncate(c.channelTitle, 24)) + '</td>' +
    '<td style="padding:8px;color:#fff">' + c.videoCount + '</td>' +
    '<td style="padding:8px;color:#fff">' + fmt(c.totalViews) + '</td>' +
    '<td style="padding:8px;color:#fff">' + (c.topVideo ? esc(truncate(c.topVideo.title, 38)) : '-') + '</td>' +
  '</tr>'
).join('');

const recsHtml = (analysis.contentRecommendations || []).map((r, i) =>
  '<div style="background:#1a1a1a;border-radius:4px;padding:16px;margin-bottom:8px;display:flex;gap:12px;align-items:flex-start">' +
    '<div style="width:24px;height:24px;border-radius:50%;background:#E2F23D;color:#000;font-weight:bold;font-size:10px;text-align:center;line-height:24px;flex-shrink:0">' + (i + 1) + '</div>' +
    '<div style="flex:1">' +
      '<div style="font-size:10.5px;font-weight:bold;color:#fff;margin-bottom:4px">' + esc(r.title || '') + '</div>' +
      '<div style="font-size:9px;color:#9ca3af;line-height:1.5;margin-bottom:6px">' + esc(r.rationale || '') + '</div>' +
      (r.targetKeywords?.length ?
        '<div style="display:flex;gap:4px;flex-wrap:wrap">' + r.targetKeywords.map(k =>
          '<span style="font-family:Courier New,monospace;font-size:6.5px;color:#E2F23D;border:0.7px solid #E2F23D;border-radius:6px;padding:2px 6px">' + esc(k) + '</span>'
        ).join('') + '</div>'
      : '') +
    '</div>' +
  '</div>'
).join('');

// ── CSS ──
